const add = function(a, b) {
	return a + b;
};

const subtract = function(a, b) {
  return a - b;
};

const sum = function(numbers) {
	let sum = 0;
  for(number of numbers) {
    sum += number;
  }
  return sum;
};

const multiply = function(numbers) {
  let multiplication = 1;
  for(number of numbers) {
    multiplication *= number;
  }
  return multiplication;
};

